exports.handler = async (event) => {
    const request = event.Records[0].cf.request;
    const response = event.Records[0].cf.response;
    
    // Check if response is HTML
    const contentType = response.headers['content-type']?.[0]?.value || '';
    if (!contentType.includes('text/html')) {
        return response;
    }
    
    // Parse custom headers for injection points
    const injectionHeaders = {};
    for (const [key, value] of Object.entries(request.headers)) {
        if (key.toLowerCase().startsWith('x-inject-')) {
            const injectionPoint = key.toLowerCase().replace('x-inject-', '');
            injectionHeaders[injectionPoint] = value[0].value;
        }
    }
    
    // Get response body
    let body = response.body;
    if (response.bodyEncoding === 'base64') {
        body = Buffer.from(response.body, 'base64').toString('utf-8');
    }
    
    // Secure HTML injection
    let modifiedBody = body;
    
    // Process each injection point
    for (const [point, content] of Object.entries(injectionHeaders)) {
        // Validate injection point name
        if (!/^[a-zA-Z0-9_-]+$/.test(point)) {
            continue;
        }
        
        // Validate content length
        if (content.length > 10000) {
            continue;
        }
        
        // Escape HTML content to prevent XSS
        const escapedContent = content
            .replace(/&/g, '&amp;')
            .replace(/</g, '&lt;')
            .replace(/>/g, '&gt;')
            .replace(/"/g, '&quot;')
            .replace(/'/g, '&#x27;');
        
        // Find and replace injection points
        const regex = new RegExp(`<!--\\s*inject:${point}\\s*-->(.*?)<!--\\s*/inject:${point}\\s*-->`, 'gs');
        modifiedBody = modifiedBody.replace(regex, `$1${escapedContent}`);
    }
    
    // Update response
    const modifiedResponse = {
        ...response,
        body: modifiedBody,
        bodyEncoding: 'text'
    };
    
    return modifiedResponse;
};